      "follow_a_red_blood_cell_through_the_en": "Urmărește o eritrocită prin întregul sistem circulator.",
      "right_atrium": "Atriul drept",
      "deoxygenated_blood_from_the_body_enter": "Sângele dezoxigenat din corp intră în atriul drept prin venele cave superioară și inferioară.",
      "right_ventricle": "Ventriculul drept",
      "blood_passes_through_the_tricuspid_val": "Sângele trece prin valva tricuspidă în ventriculul drept, care îl pompează spre plămâni.",
      "pulmonary_arteries_2": "Artere pulmonare",
      "the_right_ventricle_ejects_blood_throu": "Ventriculul drept ejectează sângele prin valva pulmonară în arterele pulmonare spre ambii plămâni.",
      "lung_capillaries": "Capilare pulmonare",
      "in_the_alveolar_capillaries_co2_is_rel": "În capilarele alveolare, CO2 este eliberat și O2 este captat prin subțirea membrană alveolară.",
      "pulmonary_veins": "Vene pulmonare",
      "freshly_oxygenated_blood_returns_to_th": "Sângele proaspăt oxigenat se întoarce la inimă prin cele patru vene pulmonare.",
      "left_atrium": "Atriul stâng",
      "the_four_pulmonary_veins_empty_oxygena": "Cele patru vene pulmonare varsă sângele oxigenat în atriul stâng, care se umple și apoi îl împinge prin valva mitrală.",
      "left_ventricle": "Ventriculul stâng",
      "blood_passes_through_the_mitral_valve_": "Sângele trece prin valva mitrală în musculosul ventricul stâng, cea mai puternică cameră cardiacă.",
      "aorta_2": "Aortă",
      "the_left_ventricle_powerfully_ejects_b": "Ventriculul stâng ejectează puternic sângele prin valva aortică în aortă, autostrada principală a corpului.",
      "body_tissues": "Țesuturi corporale",
      "arteries_branch_into_arterioles_and_ca": "Arterele se ramifică în arteriole și capilare unde O2 și nutrienții sunt livrați, iar CO2/deșeurile colectate.",
      "venous_return": "Întoarcere venoasă",
      "deoxygenated_blood_returns_through_ven": "Sângele dezoxigenat se întoarce prin venule și vene, ajutat de pompele musculare și valve, înapoi la atriul drept.",
      "path_of_air": "Traseul aerului",
      "trace_the_journey_of_a_breath_of_air_f": "Urmărește călătoria unei guri de aer de la nas la alveole și înapoi.",
      "nasal_cavity_2": "Cavitate nazală",
      "air_enters_through_the_nostrils_and_is": "Aerul intră prin nări și este încălzit, umidificat și filtrat de mucoase și cornete.",
      "pharynx_2": "Faringe",
      "air_passes_through_the_nasopharynx_and": "Aerul trece prin nazofaringe și orofaringe, un pasaj comun cu tractul digestiv.",
      "larynx": "Laringe",
      "air_crosses_the_vocal_cords_in_the_voi": "Aerul traversează corzile vocale în organul vocii. Epiglota protejează împotriva intrării alimentelor în calea aeriană.",
      "trachea_2": "Trahee",
      "the_trachea_windpipe_is_reinforced_by_": "Traheea este întărită de inele de cartilaj în formă de C. Cilii mișcă mucusul în sus pentru a prinde particulele.",
      "bronchi": "Bronhii",
      "the_trachea_splits_into_left_and_right": "Traheea se împarte în bronhiile principale stângă și dreaptă, fiecare intrând într-un plămân. Se ramifică în bronhiole mai mici.",
      "alveoli_2": "Alveole",
      "300_million_grape_like_sacs_where_gas_": "300 de milioane de saci asemănători ciorchinilor de struguri unde are loc schimbul de gaze. O2 difuzează în sânge; CO2 difuzează în afară. Suprafața echivalează cu un teren de tenis.",
      "exhalation": "Expirație",
      "the_diaphragm_relaxes_and_rises_reduci": "Diafragma se relaxează și urcă, reducând volumul pulmonar. Aerul bogat în CO2 este împins afară pe același traseu în sens invers.",
      "path_of_food": "Traseul alimentelor",
      "follow_a_meal_from_mouth_through_the_e": "Urmărește o masă de la gură prin întregul sistem digestiv.",
      "mouth": "Gură",
      "teeth_mechanically_break_food_down_sal": "Dinții sfărâmă mecanic alimentele. Amilaza salivară începe digestia amidonului. Limba modelează alimentele într-un bol.",
      "pharynx_esophagus": "Faringe și esofag",
      "swallowing_pushes_the_bolus_past_the_e": "Deglutiția împinge bolul dincolo de epiglotă. Undele peristaltice îl coboară pe esofagul de 25 cm în aproximativ 8 secunde.",
      "stomach_2": "Stomac",
      "gastric_acid_ph_1_5_3_5_and_pepsin_bre": "Acidul gastric (pH 1,5-3,5) și pepsina descompun proteinele. Amestecarea produce chimul în 2-4 ore.",
      "duodenum": "Duoden",
      "the_first_25cm_of_the_small_intestine_": "Primii 25 cm ai intestinului subțire primesc bilă din ficat/vezica biliară și enzime din pancreas.",
      "jejunum_ileum": "Jejun și ileon",
      "most_nutrient_absorption_occurs_here_v": "Cea mai mare parte a absorbției nutrienților are loc aici prin vilozități și microvilozități, crescând suprafața de 600 de ori. Lung de 6-7 metri.",
      "large_intestine_2": "Intestin gros",
      "water_and_electrolytes_are_reabsorbed_": "Apa și electroliții sunt reabsorbiți. Bacteriile intestinale fermentează fibrele rămase, producând vitaminele K și B12.",
      "rectum_excretion": "Rect și excreție",
      "waste_is_compacted_and_stored_in_the_r": "Deșeurile sunt compactate și stocate în rect până la defecație. Întreaga călătorie durează 24-72 de ore.",
      "path_of_a_nerve_signal": "Traseul unui semnal nervos",
      "trace_a_reflex_arc_from_stimulus_to_re": "Urmărește un arc reflex de la stimul la răspuns.",
      "receptor": "Receptor",
      "a_sensory_receptor_in_the_skin_detects": "Un receptor senzorial din piele detectează un stimul dureros (precum atingerea unei suprafețe fierbinți) și generează un semnal electric.",
      "sensory_neuron": "Neuron senzorial",
      "the_signal_travels_along_a_sensory_aff": "Semnalul călătorește de-a lungul unui neuron senzorial (aferent) spre măduva spinării cu până la 120 m/s prin conducere saltatorie.",
      "spinal_cord_2": "Măduva spinării",
      "in_the_dorsal_horn_the_sensory_neuron_": "În cornul dorsal, neuronul senzorial face sinapsă cu un interneuron. Pentru reflexe, semnalul nu trebuie să ajungă la creier.",
      "interneuron": "Interneuron",
      "the_interneuron_in_the_spinal_gray_mat": "Interneuronul din substanța cenușie medulară integrează semnalul și îl transmite unui neuron motor.",
      "motor_neuron": "Neuron motor",
      "the_motor_efferent_neuron_carries_the_": "Neuronul motor (eferent) duce semnalul de comandă din cornul ventral până la mușchiul-țintă.",
      "effector_muscle": "Efector (mușchi)",
      "acetylcholine_released_at_the_neuromus": "Acetilcolina eliberată la joncțiunea neuromusculară provoacă contracția musculară. Îți retragi mâna înainte de a simți durerea.",
